INSERT INTO `v1_ab008d9bb1f3852f55b029c58e60aa3b3ed0a5c0bbba42ec5c1e380b7b2807d6` VALUES (4100509, "ダメージ減衰", 10050902, 18, "すべてのモンスターが一度の行動で受けるダメージ値を減衰させる。ダメージ値が上昇するほど減衰率も上昇する。");
INSERT INTO `v1_ab008d9bb1f3852f55b029c58e60aa3b3ed0a5c0bbba42ec5c1e380b7b2807d6` VALUES (4100509, "物理防御力（ダウン不可）アップ", 10050903, "boss_def_lower_limit", "バトル開始時、すべてのモンスターの物理防御力をアップさせる。この効果は物理防御力ダウンの影響を受けない。");
INSERT INTO `v1_ab008d9bb1f3852f55b029c58e60aa3b3ed0a5c0bbba42ec5c1e380b7b2807d6` VALUES (4100509, "魔法防御力（ダウン不可）アップ", 10050904, "boss_magic_def_lower_limit", "バトル開始時、すべてのモンスターの魔法防御力をアップさせる。この効果は魔法防御力ダウンの影響を受けない。");
INSERT INTO `v1_ab008d9bb1f3852f55b029c58e60aa3b3ed0a5c0bbba42ec5c1e380b7b2807d6` VALUES (4100509, "ＴＰダウンカット", 10050905, "boss_tp_down_cut", "バトル開始時、すべてのモンスターがＴＰダウン\n75％カット状態になる。");
INSERT INTO `v1_ab008d9bb1f3852f55b029c58e60aa3b3ed0a5c0bbba42ec5c1e380b7b2807d6` VALUES (4100509, "ＴＰ上昇ダウン", 10050906, 3, "バトル開始時、すべてのキャラのＴＰ上昇をダウンさせる。");
